BEGIN TRY
    BEGIN TRANSACTION;

INSERT INTO dbo.PM_Answers (
    MicrossSalesOrderReference,
    PMAnswer,
    Comments,
    AnsweredBy,
    Date
)
VALUES (
    '{{ Select_POPM.selectedOptionValue }}',
    {{ Number(Select_PMAnswer.selectedOptionValue) }},
    '{{ (Input_PMComments.text || "").replace(/'/g,"''") }}',
    '{{ (appsmith.store.userContext?.name || "Unknown").replace(/'/g,"''") }}',
    GETDATE()
);

    -- 🔥 STATUS UPDATE
    IF {{ Number(Select_PMAnswer.selectedOptionValue) }} = 1
    BEGIN
        UPDATE dbo.PurchaseOrderHeader
        SET CRStatus = 'Final Acceptance'
        WHERE MicrossSalesOrderReference = '{{ Select_POPM.selectedOptionValue }}';
    END

    COMMIT;

END TRY
BEGIN CATCH
    ROLLBACK;
    SELECT ERROR_MESSAGE() AS ErrorMessage;
END CATCH;
